import { GoogleGenAI, Type } from "@google/genai";
import { StudioState, SubjectConfig, Landmark, ReferenceType } from "../types";
import { LENSES, PRODUCTION_SCALE_CONSTANT, COST_PER_IMAGE, COST_PER_VIDEO, COST_PER_1K_TOKENS } from "../constants";

async function downscaleImage(dataUrl: string, maxWidth = 512, quality = 0.7): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failure"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Reference image load failed"));
    img.src = dataUrl;
  });
}

export const analyzeBackground = async (dataUrl: string): Promise<Partial<Landmark>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const { data, mimeType } = await downscaleImage(dataUrl, 1024, 0.8);

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data, mimeType } },
        { text: "Identify key background landmarks. Provide labels, descriptions, and relative 3D positions (X: -30 to 30, Z: 20 to 100)." }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            label: { type: Type.STRING },
            description: { type: Type.STRING },
            x: { type: Type.NUMBER },
            z: { type: Type.NUMBER }
          },
          required: ["label", "description", "x", "z"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || "[]");
  } catch (e) {
    return [];
  }
};

const getShotScaleLabel = (percentage: number) => {
  if (percentage > 350) return "Extreme Close Up (ECU)";
  if (percentage > 160) return "Close Up (CU)";
  if (percentage > 140) return "Medium Close Up (MCU)";
  if (percentage > 55) return "Medium Shot (MS)";
  if (percentage > 30) return "Medium Long Shot (MLS)";
  if (percentage > 10) return "Long Shot (LS)";
  return "Wide Shot (WS)";
};

export const generateDraftPrompt = async (state: StudioState): Promise<{ script: string; cost: number; tokens: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const cam = state.cameras[state.activeCameraIndex];
  const focalLength = LENSES.find(l => l.label === cam.lens)?.mm || 50;

  const parts: any[] = [];

  // Attach grounding references
  for (const key of ['background', 'prop', 'accessories'] as ReferenceType[]) {
    if (state.references[key]?.dataUrl) {
      const { data, mimeType } = await downscaleImage(state.references[key].dataUrl!, 256, 0.4);
      parts.push({ text: `REFERENCE_GLOBAL_${key.toUpperCase()}:` }, { inlineData: { data, mimeType } });
    }
  }

  const subjectTags = [];
  for (const sub of state.subjects) {
    const dx = sub.x - cam.x;
    const dz = sub.z - cam.z;
    const dist = Math.sqrt(dx*dx + dz*dz);

    // Module 2: Scale Controller - Automatic frame height calculation
    const screenPercentage = (PRODUCTION_SCALE_CONSTANT * focalLength) / Math.max(0.1, dist);
    const shotLabel = getShotScaleLabel(screenPercentage);

    const angleToSub = (Math.atan2(dx, dz) * 180 / Math.PI + 360) % 360;
    let relAngle = (angleToSub - cam.rotation + 540) % 360 - 180;
    const side = relAngle < 0 ? "FRAME_LEFT" : "FRAME_RIGHT";

    // Module 5: Orientation Visibility - Increase gesture if character is small
    const gestureMultiplier = screenPercentage < 18 ? "EXAGGERATED" : "NATURAL";

    for (const refKey of ['character', 'costume', 'pose'] as ReferenceType[]) {
      const ref = sub.references[refKey];
      if (ref?.dataUrl) {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 256, 0.4);
        parts.push({ text: `REFERENCE_SUBJECT_${sub.id.toUpperCase()}_${refKey.toUpperCase()}:` }, { inlineData: { data, mimeType } });
      }
    }

    subjectTags.push({
      id: sub.id,
      label: sub.label,
      visual_scale: {
        frame_height_percentage: `${screenPercentage.toFixed(1)}%`,
        cinematic_label: shotLabel
      },
      spatial_pos: { x: sub.x.toFixed(2), z: sub.z.toFixed(2), distance: `${dist.toFixed(1)}m` },
      orientation: { 
        body_yaw: `${sub.rotation.toFixed(0)}deg`, 
        gaze_yaw: `${sub.gaze.toFixed(0)}deg`,
        note: "0deg = Facing Camera (South), 180deg = Facing Away (North)"
      },
      framing_side: side,
      gesture_intent: gestureMultiplier
    });
  }

  const productionSystemInstruction = `
You are a VIRTUAL PRODUCTION RENDER ENGINE. Strictly follow this 6-module pipeline.

=== PRODUCTION_PIPELINE_MODULES ===
1. SCENE ANALYZER: Extract lighting profile (direction, softness, contrast, temperature) and perspective map (horizon_y, fov) from REF_GLOBAL_BACKGROUND.
2. SCALE CONTROLLER: Strictly set subject height using 'frame_height_percentage'. 
   - Character height must come from perspective depth, NOT 2D resizing.
3. LIGHTING ADAPTATION: Match subject lighting to the environment. 
4. LENS BEHAVIOR MATCHING: Simulate properties of ${focalLength}mm lens. 
5. ORIENTATION VISIBILITY: Strictly obey body_yaw and gaze_yaw.
   - ROTATION RULE: 0 degrees is facing DIRECTLY AT THE LENS (South). 180 degrees is facing AWAY FROM LENS (North).
6. INTEGRATION PASS: Unify subject and background.

=== RENDER_BLUEPRINT ===
- CAMERA: ${cam.model} | LENS: ${focalLength}mm
- SUBJECTS: ${JSON.stringify(subjectTags)}
- LANDMARKS: ${JSON.stringify(state.landmarks.map(lm => ({ label: lm.label, x: lm.x, z: lm.z })))}

Output ONLY a JSON Render Manifest.
`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [...parts, { text: "Synthesize the Final Render Manifest JSON. Use all production modules. Ensure rotation is calculated such that 0deg faces the lens." }] 
    },
    config: { 
      systemInstruction: productionSystemInstruction,
      responseMimeType: "application/json"
    }
  });

  const text = response.text || "{}";
  const tokens = Math.ceil(text.length / 4) + 2000;
  return { script: text, cost: (tokens / 1000) * COST_PER_1K_TOKENS, tokens };
};

export const generateStudioImage = async (state: StudioState, draftJson: string): Promise<{ url: string; cost: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const cam = state.cameras[state.activeCameraIndex];
  const focalLength = LENSES.find(l => l.label === cam.lens)?.mm || 50;
  const parts: any[] = [];

  for (const key of ['background', 'prop', 'accessories'] as ReferenceType[]) {
    if (state.references[key]?.dataUrl) {
      const { data, mimeType } = await downscaleImage(state.references[key].dataUrl!, 512, 0.6);
      parts.push({ text: `REF_GLOBAL_${key.toUpperCase()}:` }, { inlineData: { data, mimeType } });
    }
  }

  for (const sub of state.subjects) {
    for (const refKey of ['character', 'costume', 'pose'] as ReferenceType[]) {
      const ref = sub.references[refKey];
      if (ref?.dataUrl) {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.6);
        parts.push({ text: `REF_SUB_${sub.id.toUpperCase()}_${refKey.toUpperCase()}:` }, { inlineData: { data, mimeType } });
      }
    }
  }

  parts.push({ text: `FINAL_RENDER_MANIFEST: ${draftJson}\n\nSTRICT REQUIREMENT: Use the Scene Analyzer and Scale Controller data to render character size perfectly. Apply orientation such that 0deg is facing the lens. Apply 'contact_physics' and 'lens_matching' for ${focalLength}mm.` });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { 
      imageConfig: { aspectRatio: "16:9", imageSize: "1K" } 
    }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Production Render Failed.");
  return { url: `data:image/png;base64,${imgPart.inlineData.data}`, cost: COST_PER_IMAGE };
};

export const generateStudioVideo = async (state: StudioState, script: string, baseImage: string, onStatusChange: (s: string) => void): Promise<{ url: string; cost: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const base64Data = baseImage.split(',')[1];

  let animationPrompt = script;
  try {
    const json = JSON.parse(script);
    animationPrompt = json.cinematic_description || "Animate cinematic motion matching the render manifest.";
  } catch (e) {}

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: `Motion synthesis based on production physics: ${animationPrompt}`,
    image: { imageBytes: base64Data, mimeType: 'image/png' },
    config: { resolution: '720p', aspectRatio: '16:9' }
  });

  while (!operation.done) {
    onStatusChange("Synthesizing Motion Physics...");
    await new Promise(r => setTimeout(r, 10000));
    operation = await ai.operations.getVideosOperation({ operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await videoResponse.blob();
  return { url: URL.createObjectURL(blob), cost: COST_PER_VIDEO };
};

import { Camera, MapPin, Eye, Move } from 'lucide-react';
import React, { useCallback, useEffect, useRef, useState } from 'react';
import { CameraConfig, StudioState, SubjectConfig, Landmark } from '../types';

interface FloorPlannerProps {
  state: StudioState;
  onUpdateSubject: (id: string, updates: Partial<SubjectConfig>) => void;
  onUpdateLandmark: (id: string, updates: Partial<Landmark>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onUpdatePlanner: (updates: { zoom?: number; offset?: { x: number; z: number } }) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  state, onUpdateSubject, onUpdateLandmark, onUpdateCamera, onUpdatePlanner, onSelectCamera 
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [activeDrag, setActiveDrag] = useState<{ 
    type: 'move' | 'rotate-body' | 'rotate-gaze' | 'pan' | 'pinch'; 
    target: 'subject' | 'camera' | 'landmark' | 'background';
    id: any;
    startX: number;
    startY: number;
    initialOffset: { x: number; z: number };
    initialDist?: number;
    initialZoom?: number;
  } | null>(null);

  const getRange = useCallback(() => 50 / state.plannerZoom, [state.plannerZoom]);

  const handleStart = (type: 'move' | 'rotate-body' | 'rotate-gaze' | 'pan', target: any, id: any) => (e: React.MouseEvent | React.TouchEvent) => {
    if (e.cancelable) e.preventDefault();
    e.stopPropagation();

    const clientX = 'clientX' in e ? e.clientX : e.touches[0].clientX;
    const clientY = 'clientY' in e ? e.clientY : e.touches[0].clientY;

    if (target === 'camera' && type === 'move') onSelectCamera(id);

    if ('touches' in e && e.touches.length === 2) {
      const dist = Math.hypot(e.touches[0].clientX - e.touches[1].clientX, e.touches[0].clientY - e.touches[1].clientY);
      setActiveDrag({ type: 'pinch', target: 'background', id: null, startX: clientX, startY: clientY, initialOffset: { ...state.plannerOffset }, initialDist: dist, initialZoom: state.plannerZoom });
      return;
    }

    setActiveDrag({ type, target, id, startX: clientX, startY: clientY, initialOffset: { ...state.plannerOffset } });
  };

  const handleMove = useCallback((clientX: number, clientY: number) => {
    if (!activeDrag || !containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const range = getRange();

    if (activeDrag.type === 'pan') {
      const dx = (clientX - activeDrag.startX) / rect.width * (range * 2);
      const dy = (clientY - activeDrag.startY) / rect.height * (range * 2);
      onUpdatePlanner({ offset: { x: activeDrag.initialOffset.x + dx, z: activeDrag.initialOffset.z - dy } });
      return;
    }

    if (activeDrag.type === 'move') {
      const x = ((clientX - rect.left) / rect.width - 0.5) * (range * 2) - state.plannerOffset.x;
      const z = (0.5 - (clientY - rect.top) / rect.height) * (range * 2) + state.plannerOffset.z;

      if (activeDrag.target === 'subject') onUpdateSubject(activeDrag.id, { x, z });
      else if (activeDrag.target === 'landmark') onUpdateLandmark(activeDrag.id, { x, z });
      else if (activeDrag.target === 'camera') onUpdateCamera(activeDrag.id, { x, z });
      return;
    }

    if (activeDrag.type === 'rotate-body' || activeDrag.type === 'rotate-gaze') {
      const targetObj: any = activeDrag.target === 'subject' 
        ? state.subjects.find(s => s.id === activeDrag.id) 
        : state.cameras[activeDrag.id];

      if (!targetObj) return;

      const objScreenX = rect.left + rect.width * (0.5 + (targetObj.x + state.plannerOffset.x) / (range * 2));
      const objScreenY = rect.top + rect.height * (0.5 - (targetObj.z + state.plannerOffset.z) / (range * 2));

      // Calibrate so Down (towards user/camera) is 0. 
      // Math.atan2(dx, -dy) where -dy is Up. This returns 0 for North (Up).
      // To make Down (y > screen_y) be 0, we flip the Y axis or add 180.
      const rawAngle = (Math.atan2(clientX - objScreenX, -(clientY - objScreenY)) * 180 / Math.PI + 360) % 360;
      const angle = (rawAngle + 180) % 360; // Shift: North(0) becomes 180, South(180) becomes 0.

      if (activeDrag.type === 'rotate-body') {
        if (activeDrag.target === 'subject') onUpdateSubject(activeDrag.id, { rotation: angle });
        else if (activeDrag.target === 'camera') onUpdateCamera(activeDrag.id, { rotation: angle });
      } else {
        onUpdateSubject(activeDrag.id, { gaze: angle });
      }
    }
  }, [activeDrag, state, getRange, onUpdatePlanner, onUpdateSubject, onUpdateLandmark, onUpdateCamera]);

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => handleMove(e.clientX, e.clientY);
    const onTouchMove = (e: TouchEvent) => {
      if (e.cancelable) e.preventDefault();
      if (e.touches.length === 2 && activeDrag?.type === 'pinch') {
        const dist = Math.hypot(e.touches[0].clientX - e.touches[1].clientX, e.touches[0].clientY - e.touches[1].clientY);
        const scale = dist / (activeDrag.initialDist || 1);
        onUpdatePlanner({ zoom: Math.max(0.1, Math.min(5, (activeDrag.initialZoom || 1) * scale)) });
      } else if (e.touches.length > 0) {
        handleMove(e.touches[0].clientX, e.touches[0].clientY);
      }
    };
    const onEnd = () => setActiveDrag(null);

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onEnd);
    window.addEventListener('touchmove', onTouchMove, { passive: false });
    window.addEventListener('touchend', onEnd);
    window.addEventListener('touchcancel', onEnd);

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onEnd);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('touchend', onEnd);
      window.removeEventListener('touchcancel', onEnd);
    };
  }, [activeDrag, handleMove, onUpdatePlanner]);

  const getPos = (obj: { x: number, z: number }) => {
    const range = getRange();
    const left = (((obj.x + state.plannerOffset.x) / (range * 2)) + 0.5) * 100;
    const bottom = (((obj.z + state.plannerOffset.z) / (range * 2)) + 0.5) * 100;
    return { left: `${left}%`, bottom: `${bottom}%` };
  };

  return (
    <div 
      ref={containerRef} 
      onMouseDown={handleStart('pan', 'background', null)} 
      onTouchStart={handleStart('pan', 'background', null)}
      className="w-full h-full relative overflow-hidden bg-[#050505] cursor-grab active:cursor-grabbing touch-none select-none"
      style={{ touchAction: 'none' }}
    >
      <div 
        className="absolute inset-0 opacity-10 pointer-events-none" 
        style={{ 
          backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', 
          backgroundSize: `${20 * state.plannerZoom}px ${20 * state.plannerZoom}px`, 
          backgroundPosition: `${(state.plannerOffset.x * 10 * state.plannerZoom) + (containerRef.current?.offsetWidth || 0) / 2}px ${(-state.plannerOffset.z * 10 * state.plannerZoom) + (containerRef.current?.offsetHeight || 0) / 2}px` 
        }} 
      />

      {state.subjects.map(sub => (
        <div key={sub.id} style={getPos(sub)} className="absolute -translate-x-1/2 translate-y-1/2 z-20">
          <div className="relative w-24 h-24 flex items-center justify-center pointer-events-none">
            <div 
              onMouseDown={handleStart('move', 'subject', sub.id)} 
              onTouchStart={handleStart('move', 'subject', sub.id)}
              className="absolute w-12 h-12 rounded-full border-2 border-indigo-500 bg-indigo-500/20 cursor-move pointer-events-auto shadow-[0_0_15px_rgba(99,102,241,0.3)] z-10"
            />

            {/* 0deg = South/Down. SVG is designed facing North (top). Add 180 to rotation to point Down at 0deg. */}
            <div className="absolute inset-0 pointer-events-none" style={{ transform: `rotate(${sub.rotation + 180}deg)` }}>
               <div 
                 onMouseDown={handleStart('rotate-body', 'subject', sub.id)} 
                 onTouchStart={handleStart('rotate-body', 'subject', sub.id)} 
                 className="absolute top-0 left-1/2 -translate-x-1/2 w-8 h-8 flex items-center justify-center cursor-pointer pointer-events-auto group"
               >
                 <div className="w-4 h-4 bg-indigo-500 rounded-full border border-white group-hover:scale-125 transition-transform" />
               </div>
            </div>

            <div className="absolute inset-2 pointer-events-none" style={{ transform: `rotate(${sub.gaze + 180}deg)` }}>
               <div 
                onMouseDown={handleStart('rotate-gaze', 'subject', sub.id)} 
                onTouchStart={handleStart('rotate-gaze', 'subject', sub.id)} 
                className="absolute top-0 left-1/2 -translate-x-1/2 w-8 h-8 flex items-center justify-center cursor-pointer pointer-events-auto group"
               >
                 <Eye className="w-5 h-5 text-emerald-400 group-hover:scale-125 transition-transform" />
               </div>
            </div>

            <span className="absolute top-full mt-4 text-[9px] font-black uppercase text-indigo-400 whitespace-nowrap bg-black/80 px-2 py-0.5 rounded border border-white/5 shadow-xl">
              {sub.label}
            </span>
          </div>
        </div>
      ))}

      {state.landmarks.map(lm => (
        <div key={lm.id} style={getPos(lm)} className="absolute -translate-x-1/2 translate-y-1/2 z-10">
          <div 
            onMouseDown={handleStart('move', 'landmark', lm.id)} 
            onTouchStart={handleStart('move', 'landmark', lm.id)} 
            className="flex flex-col items-center cursor-move p-2"
          >
            <MapPin className="w-8 h-8 text-emerald-500/50 drop-shadow-[0_0_8px_rgba(16,185,129,0.3)]" />
            <span className="text-[7px] font-black uppercase text-emerald-500 whitespace-nowrap bg-black/80 px-1.5 py-0.5 rounded border border-white/5 mt-1">
              {lm.label}
            </span>
          </div>
        </div>
      ))}

      {state.cameras.map((cam, idx) => (
        <div key={cam.id} style={getPos(cam)} className={`absolute -translate-x-1/2 translate-y-1/2 z-30 transition-all ${idx === state.activeCameraIndex ? 'opacity-100 scale-110' : 'opacity-30 scale-100'}`}>
          <div 
            onMouseDown={handleStart('move', 'camera', idx)} 
            onTouchStart={handleStart('move', 'camera', idx)} 
            className="relative w-16 h-16 flex items-center justify-center cursor-move"
          >
            <Camera className="w-10 h-10 text-white drop-shadow-[0_0_10px_rgba(255,255,255,0.4)]" />
            <div className="absolute inset-0 pointer-events-none" style={{ transform: `rotate(${cam.rotation + 180}deg)` }}>
              <div 
                onMouseDown={handleStart('rotate-body', 'camera', idx)} 
                onTouchStart={handleStart('rotate-body', 'camera', idx)} 
                className="absolute top-0 left-1/2 -translate-x-1/2 w-8 h-8 flex items-center justify-center cursor-pointer pointer-events-auto group"
              >
                <div className="w-3 h-3 bg-white rounded-full border-2 border-indigo-500 group-hover:scale-125 transition-transform" />
              </div>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

